CREATE OR REPLACE FUNCTION fpa_tel_get_member_status (as_memno char) RETURNS char AS $body$
DECLARE

  ls_mem_status char;


BEGIN
  select member_status_code into STRICT ls_mem_status
  from sc_mem_m_membership_registered
  where membership_no = as_memno
;
  if coalesce(ls_mem_status::text, '') = '' then ls_mem_status := ' ';end if;
  return ls_mem_status;

end;
$body$
